
.page-root {
  display: flex;
  flex-direction: column;
  height: 100%;
  padding: 12px 18px 8px;
  overflow-y: auto;
  gap: 10px;
  font-weight: 300;
}
.top-bar {
  display: flex;
  gap: 8px;
  flex-shrink: 0;
}
.top-card {
  flex: 1;
  display: flex;
  align-items: center;
  gap: 7px;
  padding: 7px 10px;
  border: 1px solid rgba(38, 38, 38, 0.5);
  background: rgba(0, 0, 0, 0.3);
}
.tc-icon {
  width: 30px;
  height: 30px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 2px;
  font-size: 0.75rem;
  flex-shrink: 0;
}
.enl .tc-icon {
  background: rgba(207, 200, 184, 0.15);
  color: var(--c-gold);
}
.org .tc-icon {
  background: rgba(168, 51, 51, 0.15);
  color: var(--c-stamp);
}
.rt .tc-icon {
  background: rgba(58, 95, 112, 0.15);
  color: var(--c-mp);
}
.chk {
  cursor: pointer;
  border: 1px solid rgba(207, 200, 184, 0.28);
  transition:
    background 0.2s,
    border-color 0.2s;
}
.chk:hover:not(:disabled) {
  background: rgba(207, 200, 184, 0.1);
  border-color: var(--c-gold);
}
.chk:disabled {
  opacity: 0.5;
  cursor: wait;
}
.chk .tc-icon {
  background: rgba(207, 200, 184, 0.12);
  color: #d4af37;
}
.chk .tc-label,
.chk .tc-value {
  color: #d4af37;
}
.tc-body {
  display: flex;
  flex-direction: column;
  gap: 1px;
}
.tc-label {
  font-size: 0.82rem;
  color: var(--c-text-dim);
  letter-spacing: 0.1em;
  font-weight: 300;
}
.tc-value {
  font-size: 1rem;
  font-weight: 400;
  color: var(--c-text);
  font-family: var(--font-serif);
  letter-spacing: 0.04em;
}

.learned-row {
  display: flex;
  align-items: center;
  gap: 6px;
  flex-wrap: wrap;
  flex-shrink: 0;
  padding: 4px 0;
  border-bottom: 1px solid rgba(38, 38, 38, 0.3);
}
.lr-label {
  font-size: 0.6rem;
  color: var(--c-text-dim);
  letter-spacing: 0.15em;
  font-family: var(--font-serif);
  font-weight: 300;
}
.lr-none {
  font-size: 0.6rem;
  color: var(--c-text-dim);
  font-style: italic;
  font-weight: 300;
}
.lr-tag {
  font-size: 0.58rem;
  color: var(--c-gold);
  border: 1px solid rgba(207, 200, 184, 0.3);
  padding: 1px 7px;
  border-radius: 2px;
  cursor: pointer;
  font-family: var(--font-serif);
  font-weight: 400;
}
.lr-tag:hover {
  background: rgba(207, 200, 184, 0.15);
  border-color: var(--c-gold);
}
.lr-tp {
  font-style: normal;
  margin-left: 3px;
  font-size: 0.5rem;
}

.tree-wrap {
  flex: 1;
  min-height: 0;
  display: flex;
  flex-direction: column;
}
.tree-canvas {
  flex: 1;
  min-height: 260px;
  border: 1px solid rgba(38, 38, 38, 0.3);
  background:
    radial-gradient(circle at 30% 30%, rgba(90, 138, 159, 0.08) 0%, transparent 45%),
    radial-gradient(circle at 70% 70%, rgba(207, 200, 184, 0.08) 0%, transparent 45%),
    radial-gradient(circle at center, rgba(207, 200, 184, 0.08) 0%, rgba(0, 0, 0, 0.2) 60%), #1a1a1a;
  overflow: hidden;
  position: relative;
  border-radius: var(--radius-sm);
  user-select: none;
  touch-action: none;
  -webkit-user-select: none;
}
.tree-world {
  position: relative;
}
.tw-svg {
  position: absolute;
  top: 0;
  left: 0;
  pointer-events: none;
  z-index: 1;
}

.t-node {
  position: absolute;
  width: 72px;
  z-index: 10;
  cursor: pointer;
  transition:
    transform 0.18s var(--ease-out-soft),
    filter 0.18s;
  will-change: transform;
}
.t-node:hover {
  z-index: 20;
  transform: scale(1.1);
  filter: brightness(1.2);
}
.tn-name {
  display: block;
  font-size: 0.6rem;
  text-align: center;
  color: var(--c-text);
  padding: 8px 5px 6px;
  font-family: var(--font-serif);
  letter-spacing: 0.06em;
  line-height: 1.25;
  border: 1px solid rgba(207, 200, 184, 0.32);
  border-radius: var(--radius-sm);
  background:
    linear-gradient(180deg, rgba(22, 20, 25, 0.88) 0%, rgba(14, 12, 16, 0.95) 100%),
    radial-gradient(ellipse at 50% 0%, rgba(207, 200, 184, 0.08) 0%, transparent 70%);
  font-weight: 400;
  position: relative;
  box-shadow:
    inset 0 1px 0 rgba(207, 200, 184, 0.06),
    0 2px 6px rgba(0, 0, 0, 0.4);
}
.t-node.can-learn .tn-name {
  border-color: rgba(90, 138, 159, 0.45);
  color: #7ab8c8;
  background:
    linear-gradient(180deg, rgba(14, 20, 24, 0.9) 0%, rgba(10, 14, 16, 0.96) 100%),
    radial-gradient(ellipse at 50% 0%, rgba(90, 138, 159, 0.12) 0%, transparent 60%);
  box-shadow:
    inset 0 1px 0 rgba(90, 138, 159, 0.08),
    0 0 10px rgba(90, 138, 159, 0.06),
    0 2px 6px rgba(0, 0, 0, 0.4);
  animation: nodeBreathe 3s ease-in-out infinite;
}
.t-node.learned .tn-name {
  border-color: rgba(207, 200, 184, 0.55);
  color: var(--c-gold-light);
  background:
    linear-gradient(180deg, rgba(30, 26, 18, 0.9) 0%, rgba(18, 14, 8, 0.96) 100%),
    radial-gradient(ellipse at 50% 0%, rgba(207, 200, 184, 0.14) 0%, transparent 60%);
  box-shadow:
    inset 0 1px 0 rgba(207, 200, 184, 0.12),
    0 0 14px rgba(207, 200, 184, 0.12),
    0 2px 6px rgba(0, 0, 0, 0.5);
}
.t-node.locked .tn-name {
  border-color: rgba(38, 38, 38, 0.2);
  background: rgba(0, 0, 0, 0.25);
  color: var(--c-text-faint);
  box-shadow: none;
}
.t-node.locked {
  opacity: 0.52;
}
.t-node:hover .tn-name {
  border-color: rgba(207, 200, 184, 0.65);
}
.t-node.can-learn:hover .tn-name {
  border-color: rgba(90, 138, 159, 0.7);
  animation: none;
  box-shadow:
    inset 0 1px 0 rgba(90, 138, 159, 0.15),
    0 0 18px rgba(90, 138, 159, 0.16),
    0 3px 10px rgba(0, 0, 0, 0.5);
}
.t-node.learned:hover .tn-name {
  box-shadow:
    inset 0 1px 0 rgba(207, 200, 184, 0.18),
    0 0 20px rgba(207, 200, 184, 0.2),
    0 3px 10px rgba(0, 0, 0, 0.5);
}
.tn-name::after {
  content: '';
  position: absolute;
  bottom: 4px;
  left: 50%;
  transform: translateX(-50%);
  width: 16px;
  height: 1px;
  background: rgba(207, 200, 184, 0.18);
  border-radius: 1px;
}
.t-node.learned .tn-name::after {
  background: rgba(207, 200, 184, 0.35);
  width: 20px;
}
.t-node.can-learn .tn-name::after {
  background: rgba(90, 138, 159, 0.25);
}
.t-node.locked .tn-name::after {
  opacity: 0;
}
@keyframes nodeBreathe {
  0%,
  100% {
    box-shadow:
      inset 0 1px 0 rgba(90, 138, 159, 0.08),
      0 0 10px rgba(90, 138, 159, 0.06),
      0 2px 6px rgba(0, 0, 0, 0.4);
  }
  50% {
    box-shadow:
      inset 0 1px 0 rgba(90, 138, 159, 0.12),
      0 0 16px rgba(90, 138, 159, 0.12),
      0 2px 6px rgba(0, 0, 0, 0.4);
  }
}
.tn-cost {
  display: block;
  font-size: 0.4rem;
  text-align: center;
  color: var(--c-gold-dim);
  margin-top: 3px;
  font-weight: 300;
  letter-spacing: 0.05em;
}
.t-node.can-learn .tn-cost {
  color: rgba(122, 184, 200, 0.65);
}
.t-node.locked .tn-cost {
  opacity: 0.25;
}
.tn-type {
  position: absolute;
  top: 2px;
  left: 4px;
  font-size: 0.48rem;
  line-height: 1;
  font-weight: 400;
  z-index: 2;
}
.tp-a {
  color: #c4785e;
}
.tp-p {
  color: #6a9aaa;
}
.tn-lv {
  position: absolute;
  top: 8px;
  right: 4px;
  font-size: 0.34rem;
  color: var(--c-text-dim);
  opacity: 0.6;
  font-weight: 300;
}
.t-node.learned .tn-lv {
  color: var(--c-gold);
  opacity: 0.85;
}
.t-node.can-learn .tn-lv {
  color: rgba(122, 184, 200, 0.55);
}
.tree-hint {
  text-align: center;
  font-size: 0.5rem;
  color: var(--c-text-dim);
  opacity: 0.35;
  padding: 2px 0 0;
  flex-shrink: 0;
  font-weight: 300;
}
.empty {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
  color: var(--c-text-dim);
  font-family: var(--font-serif);
  font-size: 0.85rem;
  font-weight: 300;
}

.dlg-bg {
  position: absolute;
  inset: 0;
  background: rgba(0, 0, 0, 0.88);
  z-index: 50;
  display: flex;
  align-items: center;
  justify-content: center;
  backdrop-filter: blur(4px);
}
.dlg {
  width: 340px;
  background: var(--c-panel);
  border: 1px solid rgba(38, 38, 38, 0.5);
  box-shadow: 0 0 40px rgba(0, 0, 0, 0.8);
  position: relative;
  animation: mi 0.18s ease;
  font-weight: 300;
}
@keyframes mi {
  from {
    opacity: 0;
    transform: scale(0.95);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}
.dlg-x {
  position: absolute;
  top: 7px;
  right: 9px;
  background: none;
  border: none;
  color: var(--c-text-dim);
  font-size: 1.1rem;
  cursor: pointer;
}
.dlg-x:hover {
  color: var(--c-gold);
}
.dlg-h {
  padding: 11px 14px;
  border-bottom: 1px solid rgba(38, 38, 38, 0.5);
  background: rgba(0, 0, 0, 0.4);
  font-size: 0.9rem;
  font-family: var(--font-serif);
  color: var(--c-text);
  letter-spacing: 0.08em;
  font-weight: 400;
}
.dlg-b {
  padding: 11px 14px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.dr {
  display: flex;
  justify-content: space-between;
  font-size: 0.72rem;
  padding: 2px 0;
  font-weight: 300;
}
.dl {
  color: var(--c-text-dim);
}
.dv2 {
  color: var(--c-text);
  text-align: right;
}
.gd {
  color: var(--c-gold);
}
.dd2 {
  font-size: 0.7rem;
  color: var(--c-text-dim);
  line-height: 1.45;
  padding: 6px 0;
  border-top: 1px solid rgba(38, 38, 38, 0.3);
  font-weight: 300;
}
.bl {
  width: 100%;
  padding: 7px;
  margin-top: 5px;
  border: 1px solid var(--c-gold);
  background: rgba(207, 200, 184, 0.12);
  color: var(--c-gold);
  font-family: var(--font-serif);
  font-size: 0.78rem;
  letter-spacing: 0.08em;
  cursor: pointer;
  font-weight: 400;
}
.bl:hover {
  background: rgba(207, 200, 184, 0.22);
}
.bx {
  text-align: center;
  padding: 8px;
  color: var(--c-text-dim);
  font-size: 0.7rem;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 5px;
  border: 1px solid rgba(38, 38, 38, 0.3);
  margin-top: 5px;
  font-weight: 300;
}
.by {
  text-align: center;
  padding: 8px;
  color: var(--c-gold);
  font-size: 0.78rem;
  border: 1px solid rgba(207, 200, 184, 0.3);
  margin-top: 5px;
  font-family: var(--font-serif);
  font-weight: 400;
}

/* ===== 手机端适配 ===== */
@media (max-width: 500px) {
  .page-root {
    padding: 8px 10px 6px;
    gap: 8px;
  }
  .top-bar {
    gap: 5px;
  }
  .top-card {
    padding: 5px 6px;
    gap: 5px;
  }
  .tc-icon {
    width: 24px;
    height: 24px;
    font-size: 0.65rem;
  }
  .tc-label {
    font-size: 0.68rem;
  }
  .tc-value {
    font-size: 0.82rem;
  }
  .learned-row {
    gap: 4px;
    padding: 3px 0;
  }
  .lr-label,
  .lr-none {
    font-size: 0.55rem;
  }
  .lr-tag {
    font-size: 0.52rem;
    padding: 1px 5px;
  }
  .tree-canvas {
    min-height: 200px;
    border-radius: var(--radius-xs);
  }
  .t-node {
    width: 68px;
  }
  .tn-name {
    font-size: 0.58rem;
    padding: 7px 4px 5px;
  }
  .tn-cost {
    font-size: 0.38rem;
    margin-top: 2px;
  }
  .tn-type {
    font-size: 0.44rem;
  }
  .tn-lv {
    font-size: 0.32rem;
    top: 7px;
  }
  .tree-hint {
    font-size: 0.45rem;
  }
  .dlg {
    width: auto;
    max-width: 92vw;
    margin: 0 12px;
  }
  .dlg-h {
    font-size: 0.82rem;
    padding: 9px 12px;
  }
  .dlg-b {
    padding: 9px 12px;
  }
  .dr {
    font-size: 0.65rem;
  }
  .dd2 {
    font-size: 0.62rem;
  }
  .bl,
  .by,
  .bx {
    font-size: 0.7rem;
  }
}

/* 触摸设备上禁用 hover 粘滞：通过 @media 精确匹配 */
@media (hover: none) {
  .t-node:hover {
    transform: none;
    filter: none;
  }
  .t-node:active {
    transform: scale(1.06);
    filter: brightness(1.15);
  }
}
