  margin-bottom: 4px;
  animation: inv-empty-float 4s ease-in-out infinite;
}
@keyframes inv-empty-float {
  0%,
  100% {
    transform: translateY(0) rotate(-4deg);
  }
  50% {
    transform: translateY(-4px) rotate(4deg);
  }
}
.inv-empty-sub {
  font-size: 0.6rem;
  opacity: 0.55;
  letter-spacing: 0.2em;
  font-style: normal;
}

/* ===== 装备选择弹窗 ===== */
.equip-modal-overlay {
  position: absolute;
  inset: 0;
  background: rgba(0, 0, 0, 0.85);
  z-index: 50;
  display: flex;
  align-items: center;
