  animation: modal-in 0.2s ease;
}

.equip-modal-close {
  position: absolute;
  top: 10px;
  right: 12px;
  background: none;
  border: none;
  color: var(--c-text-dim);
  font-size: 1.3rem;
  cursor: pointer;
