.avatar-page-note {
  margin: 0;
  font-size: var(--fs-2xs);
  color: var(--c-text-faint);
  font-family: var(--font-ui);
  letter-spacing: 0.05em;
  line-height: 1.5;
}

.avatar-page-actions {
  display: flex;
  gap: 12px;
  margin-top: 6px;
}

.avatar-page-btn {
  padding: 9px 26px;
  border: 1px solid var(--c-border);
  border-radius: var(--radius-xs);
  font-size: var(--fs-sm);
  font-family: var(--font-ui);
  letter-spacing: 0.12em;
  transition: all 0.2s;
  &.cancel {
    background: transparent;
    color: var(--c-text-dim);
    &:hover { color: var(--c-text); }
  }
  &.confirm {
    background: rgba(207, 200, 184, 0.12);
    color: var(--c-gold);
    border-color: var(--c-gold);
    &:hover:not(:disabled) { background: rgba(207, 200, 184, 0.25); }
    &:disabled { opacity: 0.3; cursor: not-allowed; }
  }
}

/* ============ 手机端适配 ============ */
@media (max-width: 500px) {
  .page-root {
    flex-direction: column;
    overflow: visible;
    height: auto;
  }

  .left-col {
    width: 100%;
    border-right: none;
    border-bottom: 1px solid rgba(180, 180, 190, 0.2);
    padding: 16px 12px;
    flex-shrink: 0;
    overflow: visible;
  }

  .right-col {
    padding: 14px 12px;
    gap: 12px;
    overflow-y: visible;
    flex: none;
  }

  .col-sep {
    display: none;
  }

  .avatar-section {
    margin-bottom: 10px;
  }
  .portrait-frame {
    width: 100px;
    height: 100px;
    padding: 4px;
    margin-bottom: 12px;
  }
  .portrait-icon {
    font-size: 2.2rem;
  }
  .protag-name {
    font-size: 1rem;
  }
  .protag-title {
    font-size: 0.68rem;
  }
  .protag-realm {
    font-size: 0.7rem;
  }
  .cultivation-card {
    max-width: 160px;
    padding: 4px 8px;
  }
  .cultivation-realm {
    font-size: 0.68rem;
  }
  .cultivation-value {
    font-size: 0.55rem;
  }
  .cultivation-track {
    height: 3px;
  }

  .radar-section {
    max-width: 180px;
  }

  .stats-grid {
    gap: 10px 12px;
  }

  /* 装备包裹：手机端纵向堆叠 - 神契横条在上、装备网格在下 */
  .equip-wrapper {
    flex-direction: column;
    align-items: center;
    gap: 10px;
  }

  .shenqi-slot {
    width: 100%;
    flex-direction: row;
    justify-content: center;
    gap: 10px;
    padding: 8px 10px;
    border: 1px solid rgba(168, 50, 50, 0.18);
    border-radius: var(--radius-sm);
    background: rgba(168, 50, 50, 0.04);
  }
  .sq-icon-wrap {
    width: 40px;
    height: 40px;
    flex-shrink: 0;
  }
  .sq-icon {
    font-size: 1rem;
  }
  .sq-label {
    font-size: 0.65rem;
    order: -1;
  }
  .sq-name {
    font-size: 0.6rem;
  }
  .sq-empty {
    font-size: 0.55rem;
  }

  .equip-grid {
    width: 100%;
    grid-template-columns: repeat(3, 1fr);
    gap: 8px 10px;
  }

  .equip-slot {
    padding: 5px 2px;
    gap: 4px;
  }
  .slot-icon-wrap {
    width: 48px;
    height: 48px;
  }
  .slot-icon {
    font-size: 1.2rem;
  }
  .slot-label {
    font-size: 0.65rem;
  }
  .slot-name {
    font-size: 0.55rem;
  }

  .section-head {
    font-size: 1rem;
    margin-bottom: 10px;
  }

  .bag-btn {
    font-size: 0.78rem;
    padding: 10px;
    letter-spacing: 0.18em;
    margin-top: 4px;
  }

  .currency-row {
    padding: 8px 12px;
    gap: 10px;
    margin-top: 8px;
  }
  .currency-value {
    font-size: 1.05rem;
  }
  .currency-label {
    font-size: 0.78rem;
  }
  .currency-icon {
    font-size: 0.95rem;
  }

  /* 背包弹窗 — 占满屏幕、自适应列数 */
  .inv-modal {
    width: 96vw;
    max-height: 82vh;
    border-radius: var(--radius-sm);
  }
  .inv-modal-header {
    font-size: 0.88rem;
    padding: 10px 14px;
  }
  .inv-modal-body {
    padding: 8px;
  }
  .inv-grid {
    grid-template-columns: repeat(auto-fill, minmax(56px, 1fr));
    gap: 5px;
  }
  .inv-item {
    padding: 6px 3px;
    aspect-ratio: auto;
    min-height: 56px;
  }
  .inv-item-icon {
    font-size: 1rem;
    margin-bottom: 3px;
  }
  .inv-item-name {
    font-size: 0.52rem;
  }
  .inv-item-qty {
    font-size: 0.52rem;
    bottom: 2px;
    right: 3px;
  }

  /* 装备选择弹窗 */
  .equip-modal {
    width: 94vw;
    max-height: 78vh;
  }
  .equip-modal-header {
    font-size: 0.88rem;
    padding: 10px 12px;
  }
  .equip-modal-row {
    padding: 8px 10px;
  }
  .equip-modal-item-name {
    font-size: 0.78rem;
  }
  .equip-modal-item-desc {
    font-size: 0.6rem;
  }

  /* 物品详情弹窗 */
  .item-detail-modal {
    width: 94vw;
    max-height: 78vh;
  }
  .item-detail-header {
    padding: 10px 12px;
  }
  .item-detail-title {
    font-size: 0.82rem;
  }
  .item-detail-body {
    padding: 10px 12px;
  }

  /* 神契选择弹窗 */
  .sq-modal {
    width: 94vw;
    max-height: 70vh;
  }
  .sq-modal-header {
    font-size: 0.82rem;
    padding: 10px 12px;
  }
  .sq-modal-row {
    padding: 8px 10px;
    gap: 6px;
  }
  .sq-god-name {
    font-size: 0.72rem;
  }
  .sq-god-skill {
    font-size: 0.55rem;
  }

  /* 头像编辑页 */
  .avatar-page {
    padding: 14px 12px 20px;
    gap: 14px;
  }
  .avatar-page-preview .portrait-frame.large {
    width: 160px;
    height: 160px;
  }
  .avatar-page-actions {
    gap: 10px;
  }
  .avatar-page-btn {
    padding: 8px 20px;
  }
}

/* 极小屏进一步压缩 */
@media (max-width: 380px) {
  .equip-grid {
    gap: 5px 4px;
  }
  .slot-icon-wrap {
    width: 40px;
    height: 40px;
  }
  .slot-icon {
    font-size: 1rem;
  }
  .slot-label {
    font-size: 0.58rem;
  }
  .slot-name {
    font-size: 0.5rem;
  }
  .sq-icon-wrap {
    width: 36px;
    height: 36px;
  }
  .sq-icon {
    font-size: 0.9rem;
  }
  .sq-label {
    font-size: 0.6rem;
  }
  .inv-grid {
    grid-template-columns: repeat(auto-fill, minmax(48px, 1fr));
  }
  .inv-item {
    min-height: 48px;
  }
  .inv-item-icon {
    font-size: 0.88rem;
  }
  .inv-item-name {
    font-size: 0.45rem;
  }
}

/* 宽屏手机横屏 — 增大间距 */
@media (min-width: 501px) and (max-width: 680px) {
  .equip-wrapper {
    gap: 14px;
  }
  .shenqi-slot {
    width: 58px;
  }
  .sq-icon-wrap {
    width: 48px;
    height: 48px;
  }
  .sq-icon {
    font-size: 1.2rem;
  }
  .slot-icon-wrap {
    width: 52px;
    height: 52px;
  }
  .slot-icon {
    font-size: 1.35rem;
  }
  .slot-label {
    font-size: 0.68rem;
  }
  .slot-name {
    font-size: 0.58rem;
  }
  .inv-grid {
    grid-template-columns: repeat(5, 1fr);
  }
}
